class OAuth2Client {
  constructor(config) {
    this.clientId = config.clientId;
    this.clientSecret = config.clientSecret;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.tokenEndpoint = config.tokenEndpoint;
    this.scopes = config.scopes || ['openid', 'profile', 'email'];
  }

  async initiateAuth() {
    const state = this.generateState();
    const nonce = this.generateNonce();
    
    localStorage.setItem('oauth_state', state);
    localStorage.setItem('oauth_nonce', nonce);
    
    const authUrl = new URL(this.authorizationEndpoint);
    authUrl.searchParams.append('response_type', 'code');
    authUrl.searchParams.append('client_id', this.clientId);
    authUrl.searchParams.append('redirect_uri', this.redirectUri);
    authUrl.searchParams.append('scope', this.scopes.join(' '));
    authUrl.searchParams.append('state', state);
    authUrl.searchParams.append('nonce', nonce);
    
    window.location.href = authUrl.toString();
  }

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    
    if (!code || !state) {
      throw new Error('Authorization code or state missing');
    }
    
    const storedState = localStorage.getItem('oauth_state');
    if (state !== storedState) {
      throw new Error('Invalid state parameter');
    }
    
    try {
      const tokenResponse = await this.exchangeCodeForToken(code);
      this.storeTokens(tokenResponse);
      localStorage.removeItem('oauth_state');
      localStorage.removeItem('oauth_nonce');
      return tokenResponse;
    } catch (error) {
      console.error('Token exchange failed:', error);
      throw error;
    }
  }

  async exchangeCodeForToken(code) {
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: this.redirectUri
      })
    });
    
    if (!response.ok) {
      throw new Error(`Token exchange failed: ${response.status}`);
    }
    
    return response.json();
  }

  storeTokens(tokens) {
    localStorage.setItem('access_token', tokens.access_token);
    localStorage.setItem('refresh_token', tokens.refresh_token);
    localStorage.setItem('token_expires_at', Date.now() + (tokens.expires_in * 1000));
  }

  async refreshAccessToken() {
    const refreshToken = localStorage.getItem('refresh_token');
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }
    
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken
      })
    });
    
    if (!response.ok) {
      throw new Error(`Token refresh failed: ${response.status}`);
    }
    
    const tokens = await response.json();
    this.storeTokens(tokens);
    return tokens;
  }

  async getAccessToken() {
    const accessToken = localStorage.getItem('access_token');
    const expiresAt = localStorage.getItem('token_expires_at');
    
    if (!accessToken || !expiresAt) {
      return null;
    }
    
    if (Date.now() >= parseInt(expiresAt)) {
      try {
        await this.refreshAccessToken();
        return localStorage.getItem('access_token');
      } catch (error) {
        console.error('Token refresh failed:', error);
        return null;
      }
    }
    
    return accessToken;
  }

  async apiRequest(url, options = {}) {
    const accessToken = await this.getAccessToken();
    if (!accessToken) {
      throw new Error('No access token available');
    }
    
    const defaultOptions = {
      headers: {
        'Authorization': `Bearer ${accessToken}`
      }
    };
    
    const finalOptions = { ...defaultOptions, ...options };
    
    try {
      const response = await fetch(url, finalOptions);
      
      if (response.status === 401) {
        try {
          await this.refreshAccessToken();
          const refreshedAccessToken = localStorage.getItem('access_token');
          finalOptions.headers.Authorization = `Bearer ${refreshedAccessToken}`;
          return await fetch(url, finalOptions);
        } catch (refreshError) {
          console.error('Token refresh failed:', refreshError);
          throw new Error('Authentication required');
        }
      }
      
      return response;
    } catch (error) {
      throw new Error(`API request failed: ${error.message}`);
    }
  }

  generateState() {
    return Math.random().toString(36).substring(2, 15) + 
           Math.random().toString(36).substring(2, 15);
  }

  generateNonce() {
    return Math.random().toString(36).substring(2, 15) + 
           Math.random().toString(36).substring(2, 15);
  }

  logout() {
    localStorage.removeItem('access_token');
    localStorage.removeItem('refresh_token');
    localStorage.removeItem('token_expires_at');
  }
}

